import type {
  CanvasNodeConnectionEvent,
  CanvasNodeConnectionSide,
  CanvasNodeInteractionState,
  CanvasNodeStatus,
} from "@workspace/ui/components/canvas-node/canvas-node";
import type { ReactNode } from "react";

export interface EntryNodeStates {
  name: string;
  status?: CanvasNodeStatus;
}

export type EntryNodeDomainKey = "access" | "private" | "public";

export interface EntryNodeDomain {
  label: string;
  status?: CanvasNodeStatus;
  value: string;
}

export type EntryNodeDomains = Partial<
  Record<EntryNodeDomainKey, EntryNodeDomain>
>;

export type EntryNodeCopyDomainHandler = (
  key: EntryNodeDomainKey,
  value: string
) => Promise<void> | void;

export type EntryNodeStartConnectionHandler = (
  side: CanvasNodeConnectionSide,
  event: CanvasNodeConnectionEvent
) => void;

export interface EntryNodeState {
  copiedDomainKey?: EntryNodeDomainKey | null;
  domains?: EntryNodeDomains;
  states: EntryNodeStates;
}

export interface EntryNodeActions {
  copyDomain: EntryNodeCopyDomainHandler;
}

export interface EntryNodeMeta {
  copiedFeedbackMs?: number;
}

export interface EntryNodeContextValue {
  actions: EntryNodeActions;
  meta: EntryNodeMeta;
  state: EntryNodeState;
}

export interface EntryNodeProviderProps {
  children?: ReactNode;
  value: EntryNodeContextValue;
}

export interface EntryNodeRootProps {
  children?: ReactNode;
  copiedDomainKey?: EntryNodeDomainKey | null;
  copiedFeedbackMs?: number;
  defaultExpanded?: boolean;
  domains?: EntryNodeDomains;
  expanded?: boolean;
  interaction?: CanvasNodeInteractionState;
  onCopyDomain?: EntryNodeCopyDomainHandler;
  onExpandedChange?: (expanded: boolean) => void;
  onStartConnection?: EntryNodeStartConnectionHandler;
  states: EntryNodeStates;
}

import type { EntryNodeDomainKey } from "./entry-node.types";

const DOMAIN_KEYS = new Set<EntryNodeDomainKey>([
  "access",
  "private",
  "public",
]);

export function isEntryNodeDomainKey(
  input: string
): input is EntryNodeDomainKey {
  return DOMAIN_KEYS.has(input as EntryNodeDomainKey);
}

"use client";

import { createContext, use } from "react";

import type { EntryNodeContextValue } from "./entry-node.types";

export const EntryNodeContext = createContext<EntryNodeContextValue | null>(
  null
);

export function useEntryNode(): EntryNodeContextValue {
  const value = use(EntryNodeContext);

  if (!value) {
    throw new Error(
      "EntryNode: compound components must be used within EntryNode.Root"
    );
  }

  return value;
}

"use client";

import { EntryNodeContext } from "./entry-node.context";
import type { EntryNodeProviderProps } from "./entry-node.types";

export function EntryNodeProvider({ children, value }: EntryNodeProviderProps) {
  return <EntryNodeContext value={value}>{children}</EntryNodeContext>;
}

"use client";

import { CanvasNodeRoot } from "@workspace/ui/components/canvas-node/canvas-node.root";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { EntryNodeProvider } from "./entry-node.provider";
import type {
  EntryNodeContextValue,
  EntryNodeDomainKey,
  EntryNodeRootProps,
} from "./entry-node.types";

const DEFAULT_COPIED_FEEDBACK_MS = 1200;

async function copyTextToClipboard(value: string) {
  if (typeof navigator === "undefined" || !navigator.clipboard) {
    return;
  }

  await navigator.clipboard.writeText(value);
}

export function EntryNodeRoot({
  children,
  copiedDomainKey,
  copiedFeedbackMs = DEFAULT_COPIED_FEEDBACK_MS,
  defaultExpanded,
  domains,
  expanded,
  interaction,
  onCopyDomain,
  onExpandedChange,
  onStartConnection,
  states,
}: EntryNodeRootProps) {
  const [internalCopiedDomainKey, setInternalCopiedDomainKey] =
    useState<EntryNodeDomainKey | null>(null);
  const resetTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const copiedDomainControlled = copiedDomainKey !== undefined;

  useEffect(
    () => () => {
      if (resetTimerRef.current) {
        clearTimeout(resetTimerRef.current);
      }
    },
    []
  );

  const copyDomain = useCallback(
    async (key: EntryNodeDomainKey, domainValue: string) => {
      if (!domainValue) {
        return;
      }

      if (onCopyDomain) {
        await onCopyDomain(key, domainValue);
      } else {
        await copyTextToClipboard(domainValue);
      }

      if (!copiedDomainControlled) {
        setInternalCopiedDomainKey(key);

        if (resetTimerRef.current) {
          clearTimeout(resetTimerRef.current);
        }

        resetTimerRef.current = setTimeout(() => {
          setInternalCopiedDomainKey(null);
          resetTimerRef.current = null;
        }, copiedFeedbackMs);
      }
    },
    [copiedDomainControlled, copiedFeedbackMs, onCopyDomain]
  );

  const value = useMemo(
    (): EntryNodeContextValue => ({
      actions: {
        copyDomain,
      },
      meta: {
        copiedFeedbackMs,
      },
      state: {
        copiedDomainKey: copiedDomainControlled
          ? copiedDomainKey
          : internalCopiedDomainKey,
        domains,
        states,
      },
    }),
    [
      copiedDomainControlled,
      copiedDomainKey,
      copiedFeedbackMs,
      copyDomain,
      domains,
      internalCopiedDomainKey,
      states,
    ]
  );

  return (
    <CanvasNodeRoot
      defaultExpanded={defaultExpanded}
      expanded={expanded}
      interaction={interaction}
      onExpandedChange={onExpandedChange}
      onStartConnection={onStartConnection}
    >
      <EntryNodeProvider value={value}>{children}</EntryNodeProvider>
    </CanvasNodeRoot>
  );
}

"use client";

import { CanvasNode } from "@workspace/ui/components/canvas-node/canvas-node";
import { cn } from "@workspace/ui/lib/utils";
import { Router } from "lucide-react";

import { useEntryNode } from "./entry-node.context";
import { EntryNodeDomainList } from "./entry-node.domain";
import type { EntryNodeDomain } from "./entry-node.types";

function getAccessDomain(
  fallbackName: string,
  domain: EntryNodeDomain | undefined
) {
  return (
    domain ?? {
      label: "Access domain",
      value: fallbackName,
    }
  );
}

function useEntryNodeAccessDomain() {
  const {
    state: { domains, states },
  } = useEntryNode();

  return getAccessDomain(states.name, domains?.access);
}

function useEntryNodeResolvedStatus() {
  const {
    state: { states },
  } = useEntryNode();
  const accessDomain = useEntryNodeAccessDomain();

  return accessDomain.status ?? states.status ?? null;
}

export function EntryNodeContent() {
  return (
    <CanvasNode.Frame>
      <CanvasNode.ConnectionLayer />
      <CanvasNode.DragStateFrame>
        <CanvasNode.Surface>
          <CanvasNode.Header>
            <EntryNodeHeaderContent />
          </CanvasNode.Header>
          <CanvasNode.Body>
            <EntryNodeDomainList />
          </CanvasNode.Body>
        </CanvasNode.Surface>
      </CanvasNode.DragStateFrame>
      <CanvasNode.ExpandButton />
    </CanvasNode.Frame>
  );
}

export function EntryNodeHeaderContent({ className }: { className?: string }) {
  return (
    <div className={cn("canvas-node-header-content min-w-0 flex-1", className)}>
      <div className="flex min-w-0 items-center justify-between gap-2">
        <EntryNodeAccess />
        <EntryNodeStatus />
      </div>
    </div>
  );
}

export function EntryNodeAccess({ className }: { className?: string }) {
  const accessDomain = useEntryNodeAccessDomain();
  const Icon = Router;

  return (
    <span className={cn("flex min-w-0 flex-1 flex-col", className)}>
      <span className="flex min-w-0 items-center gap-2">
        <Icon aria-hidden className="size-4 shrink-0 text-zinc-50" />
        <span
          className="min-w-0 truncate font-normal text-sm text-zinc-50 leading-5"
          title={accessDomain.value}
        >
          {accessDomain.value}
        </span>
      </span>
      <span className="canvas-node-header-secondary mt-1 min-w-0 truncate font-normal text-muted-foreground text-xs leading-4">
        {accessDomain.label}
      </span>
    </span>
  );
}

export function EntryNodeStatus({ className }: { className?: string }) {
  const status = useEntryNodeResolvedStatus();

  if (!status) {
    return null;
  }

  return <CanvasNode.Status className={className} status={status} />;
}

"use client";

import { Button } from "@workspace/ui/components/button";
import { CanvasNode } from "@workspace/ui/components/canvas-node/canvas-node";
import { cn } from "@workspace/ui/lib/utils";
import { Check, Copy } from "lucide-react";

import { useEntryNode } from "./entry-node.context";
import type { EntryNodeDomain, EntryNodeDomainKey } from "./entry-node.types";

const BODY_DOMAIN_KEYS = [
  "public",
  "private",
] as const satisfies readonly EntryNodeDomainKey[];

function getBodyDomains(domains: {
  private?: EntryNodeDomain;
  public?: EntryNodeDomain;
}) {
  return BODY_DOMAIN_KEYS.flatMap((domainKey) => {
    const domain = domains[domainKey];
    return domain ? [{ domain, domainKey }] : [];
  });
}

export function EntryNodeDomainList({ className }: { className?: string }) {
  const {
    state: { domains },
  } = useEntryNode();
  const bodyDomains = getBodyDomains({
    private: domains?.private,
    public: domains?.public,
  });

  return (
    <div
      className={cn("flex min-w-0 flex-col gap-2.5 pt-2.5", className)}
      data-slot="entry-node-domain-list"
    >
      {bodyDomains.map(({ domain, domainKey }) => (
        <EntryNodeDomainSection
          domain={domain}
          domainKey={domainKey}
          key={domainKey}
        />
      ))}
    </div>
  );
}

export function EntryNodeDomainSection({
  className,
  domain,
  domainKey,
}: {
  className?: string;
  domain: EntryNodeDomain;
  domainKey: EntryNodeDomainKey;
}) {
  const {
    actions,
    state: { copiedDomainKey },
  } = useEntryNode();
  const copied = copiedDomainKey === domainKey;

  return (
    <section
      className={cn("flex min-w-0 flex-col gap-2 rounded-lg pb-1.5", className)}
      data-slot="entry-node-domain-section"
    >
      <div className="flex min-w-0 items-center justify-between gap-2">
        <span className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4">
          {domain.label}
        </span>
        <CanvasNode.StatusDot size="small" status={domain.status} />
      </div>
      <Button
        className="group flex h-7 w-full min-w-0 items-center justify-between gap-2 rounded-md border-0 bg-transparent px-2.5 py-1.5 text-left font-normal text-xs text-zinc-50 leading-4 shadow-none transition-[background,box-shadow] hover:bg-white/5 hover:text-zinc-50 focus-visible:bg-white/5 data-[copied=true]:bg-white/5"
        data-copied={copied ? "true" : undefined}
        data-slot="entry-node-domain-copy"
        onClick={() => {
          Promise.resolve(actions.copyDomain(domainKey, domain.value)).catch(
            () => undefined
          );
        }}
        onDoubleClick={(event) => {
          event.stopPropagation();
        }}
        size={null}
        title={domain.value}
        type="button"
        variant={null}
      >
        <span className="min-w-0 truncate">{domain.value}</span>
        {copied ? (
          <Check aria-hidden className="size-4 shrink-0" />
        ) : (
          <Copy
            aria-hidden
            className="size-4 shrink-0 opacity-0 transition-opacity group-hover:opacity-100 group-focus-visible:opacity-100"
          />
        )}
      </Button>
    </section>
  );
}

// biome-ignore lint/performance/noBarrelFile: entry-node public package surface
export { EntryNode, useEntryNode } from "./entry-node";
export { isEntryNodeDomainKey } from "./entry-node.guards";
export type {
  EntryNodeActions,
  EntryNodeContextValue,
  EntryNodeCopyDomainHandler,
  EntryNodeDomain,
  EntryNodeDomainKey,
  EntryNodeDomains,
  EntryNodeMeta,
  EntryNodeProviderProps,
  EntryNodeRootProps,
  EntryNodeStartConnectionHandler,
  EntryNodeState,
  EntryNodeStates,
} from "./entry-node.types";

"use client";

import {
  EntryNodeAccess,
  EntryNodeContent,
  EntryNodeHeaderContent,
  EntryNodeStatus,
} from "./entry-node.content";
import {
  EntryNodeDomainList,
  EntryNodeDomainSection,
} from "./entry-node.domain";
import { EntryNodeRoot } from "./entry-node.root";

// biome-ignore lint/performance/noBarrelFile: compound hook re-export for `import { useEntryNode }`
export { useEntryNode } from "./entry-node.context";
export type {
  EntryNodeActions,
  EntryNodeContextValue,
  EntryNodeCopyDomainHandler,
  EntryNodeDomain,
  EntryNodeDomainKey,
  EntryNodeDomains,
  EntryNodeMeta,
  EntryNodeProviderProps,
  EntryNodeRootProps,
  EntryNodeStartConnectionHandler,
  EntryNodeState,
  EntryNodeStates,
} from "./entry-node.types";

export const EntryNode = {
  Access: EntryNodeAccess,
  Content: EntryNodeContent,
  DomainList: EntryNodeDomainList,
  DomainSection: EntryNodeDomainSection,
  HeaderContent: EntryNodeHeaderContent,
  Root: EntryNodeRoot,
  Status: EntryNodeStatus,
} as const;

const dn = (component: object, name: string) => {
  (component as { displayName?: string }).displayName = name;
};

dn(EntryNodeRoot, "EntryNode.Root");
dn(EntryNodeContent, "EntryNode.Content");
dn(EntryNodeHeaderContent, "EntryNode.HeaderContent");
dn(EntryNodeAccess, "EntryNode.Access");
dn(EntryNodeStatus, "EntryNode.Status");
dn(EntryNodeDomainList, "EntryNode.DomainList");
dn(EntryNodeDomainSection, "EntryNode.DomainSection");
